// MARK: - Models

struct Stock: Codable, Identifiable, Equatable {
    let id: String
    let symbol: String
    let name: String
    var currentPrice: Double
    var previousClose: Double
    var dayHigh: Double
    var dayLow: Double
    var volume: Int
    var changePercent: Double
    var lastUpdated: Date
    
    var priceChange: Double {
        currentPrice - previousClose
    }
    
    var isPositive: Bool {
        priceChange >= 0
    }
}

enum OrderType: String, Codable, CaseIterable {
    case market = "MARKET"
    case limit = "LIMIT"
    case stopLoss = "STOP_LOSS"
    case stopLimit = "STOP_LIMIT"
}

enum OrderSide: String, Codable {
    case buy = "BUY"
    case sell = "SELL"
}

enum OrderStatus: String, Codable {
    case pending = "PENDING"
    case filled = "FILLED"
    case partiallyFilled = "PARTIALLY_FILLED"
    case cancelled = "CANCELLED"
    case rejected = "REJECTED"
    case expired = "EXPIRED"
}

enum TimeInForce: String, Codable, CaseIterable {
    case day = "DAY"
    case gtc = "GTC"
    case ioc = "IOC"
    case fok = "FOK"
}

struct TradeOrder: Codable, Identifiable {
    let id: String
    let symbol: String
    let side: OrderSide
    let type: OrderType
    let quantity: Double
    let limitPrice: Double?
    let stopPrice: Double?
    let timeInForce: TimeInForce
    var status: OrderStatus
    var filledQuantity: Double
    var averageFilledPrice: Double?
    let createdAt: Date
    var updatedAt: Date
    var executedAt: Date?
}

struct Position: Codable, Identifiable {
    let id: String
    let symbol: String
    let stockName: String
    var quantity: Double
    var averageCost: Double
    var currentPrice: Double
    
    var marketValue: Double {
        quantity * currentPrice
    }
    
    var totalCost: Double {
        quantity * averageCost
    }
    
    var unrealizedPnL: Double {
        marketValue - totalCost
    }
    
    var unrealizedPnLPercent: Double {
        guard totalCost > 0 else { return 0 }
        return (unrealizedPnL / totalCost) * 100
    }
    
    var isProfit: Bool {
        unrealizedPnL >= 0
    }
}

struct Portfolio: Codable {
    var cashBalance: Double
    var positions: [Position]
    var totalValue: Double {
        cashBalance + positions.reduce(0) { $0 + $1.marketValue }
    }
    var totalInvested: Double {
        positions.reduce(0) { $0 + $1.totalCost }
    }
    var totalPnL: Double {
        positions.reduce(0) { $0 + $1.unrealizedPnL }
    }
    var totalPnLPercent: Double {
        guard totalInvested > 0 else { return 0 }
        return (totalPnL / totalInvested) * 100
    }
    var dayChange: Double
    var dayChangePercent: Double
}

