// MARK: - Networking & Security

final class SecureAPIClient {
    static let shared = SecureAPIClient()
    
    private let session: URLSession
    private let baseURL: String
    private var authToken: String?
    private var refreshToken: String?
    private let keychain = KeychainManager.shared
    private let rateLimiter = RateLimiter()
    
    private init() {
        baseURL = "https://api.tradingplatform.com/v1"
        
        let config = URLSessionConfiguration.default
        config.tlsMinimumSupportedProtocolVersion = .TLSv12
        config.httpAdditionalHeaders = [
            "Content-Type": "application/json",
            "Accept": "application/json",
            "X-Platform": "iOS",
            "X-App-Version": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "1.0"
        ]
        config.timeoutIntervalForRequest = 15
        config.timeoutIntervalForResource = 30
        config.waitsForConnectivity = true
        
        let delegate = SSLPinningDelegate()
        session = URLSession(configuration: config, delegate: delegate, delegateQueue: nil)
        
        loadTokens()
    }
    
    private func loadTokens() {
        authToken = keychain.get("auth_token")
        refreshToken = keychain.get("refresh_token")
    }
    
    func setTokens(auth: String, refresh: String) {
        authToken = auth
        refreshToken = refresh
        keychain.set(auth, forKey: "auth_token")
        keychain.set(refresh, forKey: "refresh_token")
    }
    
    func clearTokens() {
        authToken = nil
        refreshToken = nil
        keychain.delete("auth_token")
        keychain.delete("refresh_token")
    }
    
    func request<T: Decodable>(
        endpoint: APIEndpoint,
        method: HTTPMethod = .get,
        body: Encodable? = nil,
        requiresAuth: Bool = true
    ) async throws -> T {
        guard rateLimiter.allowRequest() else {
            throw TradingError.rateLimited
        }
        
        var urlRequest = try buildRequest(endpoint: endpoint, method: method, body: body, requiresAuth: requiresAuth)
        
        let nonce = UUID().uuidString
        let timestamp = String(Int(Date().timeIntervalSince1970))
        urlRequest.addValue(nonce, forHTTPHeaderField: "X-Nonce")
        urlRequest.addValue(timestamp, forHTTPHeaderField: "X-Timestamp")
        
        let signature = generateRequestSignature(nonce: nonce, timestamp: timestamp, endpoint: endpoint.path)
        urlRequest.addValue(signature, forHTTPHeaderField: "X-Signature")
        
        let (data, response) = try await session.data(for: urlRequest)
        
        guard let httpResponse = response as? HTTPURLResponse else {
            throw TradingError.invalidResponse
        }
        
        switch httpResponse.statusCode {
        case 200...299:
            let decoder = JSONDecoder()
            decoder.dateDecodingStrategy = .iso8601
            return try decoder.decode(T.self, from: data)
        case 401:
            if requiresAuth, let _ = refreshToken {
                try await refreshAuthToken()
                return try await request(endpoint: endpoint, method: method, body: body, requiresAuth: requiresAuth)
            }
            throw TradingError.unauthorized
        case 429:
            throw TradingError.rateLimited
        case 400...499:
            let errorResponse = try? JSONDecoder().decode(APIErrorResponse.self, from: data)
            throw TradingError.apiError(errorResponse?.message ?? "Client error")
        case 500...599:
            throw TradingError.serverError
        default:
            throw TradingError.unknown
        }
    }
    
    private func buildRequest(
        endpoint: APIEndpoint,
        method: HTTPMethod,
        body: Encodable?,
        requiresAuth: Bool
    ) throws -> URLRequest {
        guard let url = URL(string: baseURL + endpoint.path) else {
            throw TradingError.invalidURL
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = method.rawValue
        
        if requiresAuth, let token = authToken {
            request.addValue("Bearer \(token)", forHTTPHeaderField: "Authorization")
        }
        
        if let body = body {
            let encoder = JSONEncoder()
            encoder.dateEncodingStrategy = .iso8601
            request.httpBody = try encoder.encode(AnyEncodable(body))
        }
        
        return request
    }
    
    private func refreshAuthToken() async throws {
        guard let refresh = refreshToken else {
            throw TradingError.unauthorized
        }
        
        struct RefreshRequest: Encodable {
            let refreshToken: String
        }
        
        struct RefreshResponse: Decodable {
            let accessToken: String
            let refreshToken: String
        }
        
        let response: RefreshResponse = try await request(
            endpoint: .refreshToken,
            method: .post,
            body: RefreshRequest(refreshToken: refresh),
            requiresAuth: false
        )
        
        setTokens(auth: response.accessToken, refresh: response.refreshToken)
    }
    
    private func generateRequestSignature(nonce: String, timestamp: String, endpoint: String) -> String {
        let message = "\(nonce):\(timestamp):\(endpoint)"
        let key = SymmetricKey(data: Data("api_signing_secret".utf8))
        let signature = HMAC<SHA256>.authenticationCode(for: Data(message.utf8), using: key)
        return Data(signature).base64EncodedString()
    }
}

struct AnyEncodable: Encodable {
    private let encode: (Encoder) throws -> Void
    
    init<T: Encodable>(_ wrapped: T) {
        encode = wrapped.encode
    }
    
    func encode(to encoder: Encoder) throws {
        try encode(encoder)
    }
}

struct APIErrorResponse: Decodable {
    let message: String
    let code: String?
}

