            localizedReason: reason
        )
    }
}

// MARK: - Trade Execution Service

final class TradeExecutionService: ObservableObject {
    static let shared = TradeExecutionService()
    
    @Published var pendingOrders: [TradeOrder] = []
    @Published var orderHistory: [TradeOrder] = []
    @Published var lastConfirmation: TradeConfirmation?
    @Published var isProcessing = false
    @Published var error: TradingError?
    
    private let apiClient = SecureAPIClient.shared
    private let biometricAuth = BiometricAuthManager.shared
    
    private init() {}
    
    struct PlaceOrderRequest: Encodable {
        let symbol: String
        let side: OrderSide
        let type: OrderType
        let quantity: Double
        let limitPrice: Double?
        let stopPrice: Double?
        let timeInForce: TimeInForce
    }
    
    func placeOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Double,
        limitPrice: Double? = nil,
        stopPrice: Double? = nil,
        timeInForce: TimeInForce = .day,
        requireBiometric: Bool = true
    ) async throws -> TradeConfirmation {
        // Validate order
        try validateOrder(symbol: symbol, side: side, type: type, quantity: quantity, limitPrice: limitPrice, stopPrice: stopPrice)
        
        // Biometric authentication for trade execution
        if requireBiometric && biometricAuth.isBiometricAvailable {
            let authenticated = try await biometricAuth.authenticate(
                reason: "Authenticate to \(side.rawValue.lowercased()) \(Int(quantity)) shares of \(symbol)"
            )
            guard authenticated else {
                throw TradingError.biometricFailed
            }
        }
        
        await MainActor.run {
            isProcessing = true
            error = nil
        }
        
        defer {
            Task { @MainActor in
                isProcessing = false
            }
        }
        
        let request = PlaceOrderRequest(
            symbol: symbol,
            side: side,
            type: type,
            quantity: quantity,
            limitPrice: limitPrice,
            stopPrice: stopPrice,
            timeInForce: timeInForce
        )
        
        let confirmation: TradeConfirmation = try await apiClient.request(
            endpoint: .placeOrder,
            method: .post,
            body: request
        )
        
        await MainActor.run {
            lastConfirmation = confirmation
        }
        
        // Refresh orders
        await refreshOrders()
        
        return confirmation
    }
    
    func cancelOrder(orderId: String) async throws {
        let _: TradeOrder = try await apiClient.request(
            endpoint: .cancelOrder(id: orderId),
            method: .post
        )
        await refreshOrders()
    }
    
    func getOrderStatus(orderId: String) async throws -> TradeOrder {
        return try await apiClient.request(endpoint: .orderStatus(id: orderId))
    }
    
    func refreshOrders() async {
        do {
            let orders: [TradeOrder] = try await apiClient.request(endpoint: .orders)
            await MainActor.run {
                self.pendingOrders = orders.filter { $0.status == .pending || $0.status == .partiallyFilled }
                self.orderHistory = orders.filter { $0.status != .pending && $0.status != .partiallyFilled }
            }
        } catch {
            print("Failed to refresh orders: \(error)")
        }
    }
    
    private func validateOrder(
        symbol: String,
        side: OrderSide,
        type: OrderType,
        quantity: Double,
        limitPrice: Double?,
        stopPrice: Double?
    ) throws {
        guard !symbol.isEmpty else {
            throw TradingError.invalidOrder
        }
        
        guard quantity > 0 else {
            throw TradingError.invalidOrder
        }
        
        switch type {
        case .limit:
            guard limitPrice != nil, limitPrice! > 0 else {
                throw TradingError.invalidOrder
            }
        case .stopLoss:
            guard stopPrice != nil, stopPrice! > 0 else {
                throw TradingError.invalidOrder
            }
        case .stopLimit:
            guard limitPrice != nil, limitPrice! > 0,
                  stopPrice != nil, stopPrice! > 0 else {
                throw TradingError.invalidOrder
            }
        case .market:
            break
        }
    }
}

