final class PortfolioManager: ObservableObject {
    static let shared = PortfolioManager()
    
    @Published var portfolio: Portfolio?
    @Published var positions: [Position] = []
    @Published var isLoading = false
    @Published var error: TradingError?
    
    private let apiClient = SecureAPIClient.shared
    private var refreshTask: Task<Void, Never>?
    
    private init() {}
    
    func loadPortfolio() async {
        await MainActor.run {
            isLoading = true
            error = nil
        }
        
        do {
            async let portfolioRequest: Portfolio = apiClient.request(endpoint: .portfolio)
            async let positionsRequest: [Position] = apiClient.request(endpoint: .positions)
            
            let (portfolio, positions) = try await (portfolioRequest, positionsRequest)
            
            await MainActor.run {
                self.portfolio = portfolio
                self.positions = positions
                self.isLoading = false
            }
        } catch let tradingError as TradingError {
            await MainActor.run {
                self.error = tradingError
                self.isLoading = false
            }
        } catch {
            await MainActor.run {
                self.error = .unknown
                self.isLoading = false
            }
        }
    }
    
    func startAutoRefresh(interval: TimeInterval = 10) {
        refreshTask?.cancel()
        refreshTask = Task {
            while !Task.isCancelled {
                await loadPortfolio()
                try? await Task.sleep(nanoseconds: UInt64(interval * 1_000_000_000))
            }
        }
    }
    
    func stopAutoRefresh() {
        refreshTask?.cancel()
        refreshTask = nil
    }
    
    func getPosition(for symbol: String) -> Position? {
        positions.first { $0.symbol == symbol }
    }
}

// MARK: - Watchlist Manager

final class WatchlistManager: ObservableObject {
    static let shared = WatchlistManager()
    
    @Published var watchlist: [WatchlistItem] = []
    @Published var isLoading = false
    
    private let apiClient = SecureAPIClient.shared
    
    private init() {}
    
    func loadWatchlist() async {
        await MainActor.run { isLoading = true }
        
        do {
            let items: [WatchlistItem] = try await apiClient.request(endpoint: .watchlist)
            await MainActor.run {
                self.watchlist = items
                self.isLoading = false
            }
        } catch {
            await MainActor.run { self.isLoading = false }
        }
    }
    
    struct AddWatchlistRequest: Encodable {
        let symbol: String
    }
    
    func addSymbol(_ symbol: String) async throws {
        let item: WatchlistItem = try await apiClient.request(
            endpoint: .addToWatchlist,
            method: .post,
            body: AddWatchlistRequest(symbol: symbol)
        )
        await MainActor.run {
            watchlist.append(item)
        }
    }
    
    func removeSymbol(_ id: String) async throws {
        let _: EmptyResponse = try await apiClient.request(
            endpoint: .removeFromWatchlist(id: id),
            method: .delete
        )
        await MainActor.run {
            watchlist.removeAll { $0.id == id }
        }
    }
}

struct EmptyResponse: Decodable {}

// MARK: - Market Data Service

final class MarketDataService: ObservableObject {
    static let shared = MarketDataService()
    
    @Published var searchResults: [Stock] = []
    @Published var chartData: [ChartDataPoint] = []
    @Published var currentQuote: PriceQuote?
    @Published var isSearching = false
    
    private let apiClient = SecureAPIClient.shared
    private var searchTask: Task<Void, Never>?
    
    private init() {}
    
    func getQuote(symbol: String) async throws -> PriceQuote {
        let quote: PriceQuote = try await apiClient.request(endpoint: .quote(symbol: symbol))
        await MainActor.run {
            self.currentQuote = quote
        }
        return quote
    }
    
    func getChartData(symbol: String, interval: String = "1D") async throws {
        let data: [ChartDataPoint] = try await apiClient.request(
            endpoint: .chartData(symbol: symbol, interval: interval)
        )
        await MainActor.run {
            self.chartData = data
        }
    }
    
    func search(query: String) {
        searchTask?.cancel()
        
        guard !query.isEmpty else {
            DispatchQueue.main.async {
                self.searchResults = []
                self.isSearching = false
            }
            return
        }
        
        searchTask = Task {
            await MainActor.run { isSearching = true }
            
            try? await Task.sleep(nanoseconds: 300_000_000) // 300ms debounce
            
            guard !Task.isCancelled else { return }
            
            do {
                let results: [Stock] = try await apiClient.request(endpoint: .search(query: query))
                await MainActor.run {
                    self.searchResults = results
                    self.isSearching = false
                }
            } catch {
                await MainActor.run { self.isSearching = false }
            }
        }
    }
}

// MARK: - UI Components

final class CurrencyFormatter {
    static let shared = CurrencyFormatter()
    
    private let formatter: NumberFormatter = {
        let f = NumberFormatter()
        f.numberStyle = .currency
        f.currencyCode = "USD"
        f.minimumFractionDigits = 2
        f.maximumFractionDigits = 2
        return f
    }()
    
    private let percentFormatter: NumberFormatter = {
        let f = NumberFormatter()
        f.numberStyle = .percent
        f.minimumFractionDigits = 2
        f.maximumFractionDigits = 2
        f.multiplier = 1
        return f
    }()
    
    func format(_ value: Double) -> String {
        formatter.string(from: NSNumber(value: value)) ?? "$0.00"
    }
    
    func formatPercent(_ value: Double) -> String {
        let prefix = value >= 0 ? "+" : ""
        return prefix + (percentFormatter.string(from: NSNumber(value: value)) ?? "0.00%")
    }
    
    func formatChange(_ value: Double) -> String {
        let prefix = value >= 0 ? "+" : ""
        return prefix + format(value)
    }
}

