// MARK: - Portfolio View Controller

class PortfolioViewController: UIViewController {
    
    private let portfolioManager = PortfolioManager.shared
    private var cancellables = Set<AnyCancellable>()
    
    private lazy var scrollView: UIScrollView = {
        let sv = UIScrollView()
        sv.translatesAutoresizingMaskIntoConstraints = false
        sv.refreshControl = refreshControl
        return sv
    }()
    
    private lazy var contentStack: UIStackView = {
        let stack = UIStackView()
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.axis = .vertical
        stack.spacing = 16
        stack.layoutMargins = UIEdgeInsets(top: 16, left: 16, bottom: 16, right: 16)
        stack.isLayoutMarginsRelativeArrangement = true
        return stack
    }()
    
    private lazy var refreshControl: UIRefreshControl = {
        let rc = UIRefreshControl()
        rc.addTarget(self, action: #selector(refreshPortfolio), for: .valueChanged)
        return rc
    }()
    
    private let totalValueLabel = UILabel()
    private let totalValueAmountLabel = UILabel()
    private let dayChangeLabel = UILabel()
    private let cashBalanceLabel = UILabel()
    private let totalPnLLabel = UILabel()
    private lazy var positionsTableView: UITableView = {
        let tv = UITableView(frame: .zero, style: .insetGrouped)
        tv.translatesAutoresizingMaskIntoConstraints = false
        tv.delegate = self
        tv.dataSource = self
        tv.register(PositionCell.self, forCellReuseIdentifier: PositionCell.identifier)
        tv.isScrollEnabled = false
        return tv
    }()
    
    private var positionsTableHeightConstraint: NSLayoutConstraint?
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Portfolio"
        view.backgroundColor = .systemGroupedBackground
        navigationController?.navigationBar.prefersLargeTitles = true
        
        setupUI()
        bindData()
        
        Task {
            await portfolioManager.loadPortfolio()
        }
    }
    
    private func setupUI() {
        view.addSubview(scrollView)
        scrollView.addSubview(contentStack)
        
        NSLayoutConstraint.activate([
            scrollView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            scrollView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            scrollView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            scrollView.bottomAnchor.constraint(equalTo: view.bottomAnchor),
            
            contentStack.topAnchor.constraint(equalTo: scrollView.topAnchor),
            contentStack.leadingAnchor.constraint(equalTo: scrollView.leadingAnchor),
            contentStack.trailingAnchor.constraint(equalTo: scrollView.trailingAnchor),
            contentStack.bottomAnchor.constraint(equalTo: scrollView.bottomAnchor),
            contentStack.widthAnchor.constraint(equalTo: scrollView.widthAnchor)
        ])
        
        // Summary Card
        let summaryCard = createSummaryCard()
        contentStack.addArrangedSubview(summaryCard)
        
        // Positions Header
        let positionsHeader = UILabel()
        positionsHeader.text = "Positions"
        positionsHeader.font = .systemFont(ofSize: 20, weight: .bold)
        contentStack.addArrangedSubview(positionsHeader)
        
        // Positions Table
        contentStack.addArrangedSubview(positionsTableView)
        positionsTableHeightConstraint = positionsTableView.heightAnchor.constraint(equalToConstant: 200)
        positionsTableHeightConstraint?.isActive = true
    }
    
    private func createSummaryCard() -> UIView {
        let card = UIView()
        card.backgroundColor = .systemBackground
        card.layer.cornerRadius = 16
        card.layer.shadowColor = UIColor.black.cgColor
        card.layer.shadowOpacity = 0.1
        card.layer.shadowRadius = 8
        card.layer.shadowOffset = CGSize(width: 0, height: 2)
        
        let stack = UIStackView()
        stack.translatesAutoresizingMaskIntoConstraints = false
        stack.axis = .vertical
        stack.spacing = 8
        stack.layoutMargins = UIEdgeInsets(top: 20, left: 20, bottom: 20, right: 20)
        stack.isLayoutMarginsRelativeArrangement = true
        
        totalValueLabel.text = "Total Portfolio Value"
        totalValueLabel.font = .systemFont(ofSize: 14, weight: .medium)
        totalValueLabel.textColor = .secondaryLabel
        
        totalValueAmountLabel.text = "$0.00"
        totalValueAmountLabel.font = .systemFont(ofSize: 34, weight: .bold)
        
        dayChangeLabel.text = "+$0.00 (0.00%)"
        dayChangeLabel.font = .systemFont(ofSize: 16, weight: .semibold)
        dayChangeLabel.textColor = .systemGreen
        
        let separator = UIView()
        separator.backgroundColor = .separator
        separator.heightAnchor.constraint(equalToConstant: 1).isActive = true
        
        let detailsStack = UIStackView()
        detailsStack.axis = .horizontal
        detailsStack.distribution = .fillEqually
        
        let cashStack = createDetailItem(title: "Cash Balance", valueLabel: cashBalanceLabel)
        let pnlStack = createDetailItem(title: "Unrealized P&L", valueLabel: totalPnLLabel)
        
        detailsStack.addArrangedSubview(cashStack)
        detailsStack.addArrangedSubview(pnlStack)
        
        stack.addArrangedSubview(totalValueLabel)
        stack.addArrangedSubview(totalValueAmountLabel)
        stack.addArrangedSubview(dayChangeLabel)
        stack.addArrangedSubview(separator)
        stack.addArrangedSubview(detailsStack)
        
        card.addSubview(stack)
        NSLayoutConstraint.activate([
            stack.topAnchor.constraint(equalTo: card.topAnchor),
            stack.leadingAnchor.constraint(equalTo: card.leadingAnchor),
            stack.trailingAnchor.constraint(equalTo: card.trailingAnchor),
            stack.bottomAnchor.constraint(equalTo: card.bottomAnchor)
        ])
        
        return card
    }
    
    private func createDetailItem(title: String, valueLabel: UILabel) -> UIStackView {
        let stack = UIStackView()
        stack.axis = .vertical
        stack.spacing = 4
        stack.alignment = .center
        
        let titleLabel = UILabel()
        titleLabel.text = title
        titleLabel.font = .systemFont(ofSize: 12, weight: .medium)
        titleLabel.textColor = .secondaryLabel
        
        valueLabel.text = "$0.00"
        valueLabel.font = .systemFont(ofSize: 16, weight: .semibold)
        
        stack.addArrangedSubview(titleLabel)
        stack.addArrangedSubview(valueLabel)
        
        return stack
    }
    
    private func bindData() {
        portfolioManager.$portfolio
            .receive(on: DispatchQueue.main)
            .sink { [weak self] portfolio in
                self?.updatePortfolioUI(portfolio)
            }
            .store(in: &cancellables)
        
        portfolioManager.$positions
            .receive(on: DispatchQueue.main)
            .sink { [weak self] positions in
                self?.positionsTableView.reloadData()
                let height = CGFloat(max(positions.count, 1)) * 80
                self?.positionsTableHeightConstraint?.constant = height + 50
            }
            .store(in: &cancellables)
        
        portfolioManager.$isLoading
            .receive(on: DispatchQueue.main)
            .sink { [weak self] isLoading in
                if !isLoading {
                    self?.refreshControl.endRefreshing()
                }
            }
            .store(in: &cancellables)
    }
    
    private func updatePortfolioUI(_ portfolio: Portfolio?) {
        guard let portfolio = portfolio else { return }
        
        let formatter = CurrencyFormatter.shared
        
        totalValueAmountLabel.text = formatter.format(portfolio.totalValue)
        
        let changeText = "\(formatter.formatChange(portfolio.dayChange)) (\(formatter.formatPercent(portfolio.dayChangePercent)))"
        dayChangeLabel.text = changeText
        dayChangeLabel.textColor = portfolio.dayChange >= 0 ? .systemGreen : .systemRed
        
        cashBalanceLabel.text = formatter.format(portfolio.cashBalance)
        
        totalPnLLabel.text = formatter.formatChange(portfolio.totalPnL)
        totalPnLLabel.textColor = portfolio.totalPnL >= 0 ? .systemGreen : .systemRed
    }
    
    @objc private func refreshPortfolio() {
        Task {
            await portfolioManager.loadPortfolio()
        }
    }
}

extension PortfolioViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        let count = portfolioManager.positions.count
        return count == 0 ? 1 : count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        if portfolioManager.positions.isEmpty {
            let cell = UITableViewCell()
            cell.textLabel?.text = "No positions yet"
            cell.textLabel?.textColor = .secondaryLabel
            cell.textLabel?.textAlignment = .center
            cell.selectionStyle = .none
            return cell
        }
        
        let cell = tableView.dequeueReusableCell(withIdentifier: PositionCell.identifier, for: indexPath) as! PositionCell
        cell.configure(with: portfolioManager.positions[indexPath.row])
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        return 80
    }
    
    func tableView(_ tableView: UITableView, didSelectRowAt indexPath: IndexPath) {
        tableView.deselectRow(at: indexPath, animated: true)
        guard !portfolioManager.positions.isEmpty else { return }
        
        let position = portfolioManager.positions[indexPath.row]
        let tradeVC = TradeExecutionViewController(symbol: position.symbol, stockName: position.stockName)
        navigationController?.pushViewController(tradeVC, animated: true)
    }
}

