            mainStack.topAnchor.constraint(equalTo: contentView.topAnchor, constant: 12),
            mainStack.leadingAnchor.constraint(equalTo: contentView.leadingAnchor, constant: 16),
            mainStack.trailingAnchor.constraint(equalTo: contentView.trailingAnchor, constant: -16),
            mainStack.bottomAnchor.constraint(equalTo: contentView.bottomAnchor, constant: -12)
        ])
        
        symbolLabel.font = .systemFont(ofSize: 16, weight: .bold)
        nameLabel.font = .systemFont(ofSize: 12, weight: .regular)
        nameLabel.textColor = .secondaryLabel
        quantityLabel.font = .systemFont(ofSize: 12, weight: .medium)
        quantityLabel.textColor = .secondaryLabel
        
        valueLabel.font = .systemFont(ofSize: 16, weight: .semibold)
        pnlLabel.font = .systemFont(ofSize: 13, weight: .medium)
        pnlPercentLabel.font = .systemFont(ofSize: 12, weight: .medium)
    }
    
    func configure(with position: Position) {
        let formatter = CurrencyFormatter.shared
        
        symbolLabel.text = position.symbol
        nameLabel.text = position.stockName
        quantityLabel.text = "\(Int(position.quantity)) shares @ \(formatter.format(position.averageCost))"
        
        valueLabel.text = formatter.format(position.marketValue)
        pnlLabel.text = formatter.formatChange(position.unrealizedPnL)
        pnlPercentLabel.text = formatter.formatPercent(position.unrealizedPnLPercent)
        
        let color: UIColor = position.isProfit ? .systemGreen : .systemRed
        pnlLabel.textColor = color
        pnlPercentLabel.textColor = color
    }
}

