            stack.addArrangedSubview(self.estimatedCostLabel)
            stack.addArrangedSubview(self.availableFundsLabel)
            stack.addArrangedSubview(self.availableSharesLabel)
            
            return stack
        }
        contentStack.addArrangedSubview(summaryCard)
        
        // Execute Button
        executeButton.setTitle("Review Order", for: .normal)
        executeButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .bold)
        executeButton.backgroundColor = .systemBlue
        executeButton.setTitleColor(.white, for: .normal)
        executeButton.layer.cornerRadius = 12
        executeButton.heightAnchor.constraint(equalToConstant: 56).isActive = true
        executeButton.addTarget(self, action: #selector(reviewOrder), for: .touchUpInside)
        contentStack.addArrangedSubview(executeButton)
        
        updateAvailableFunds()
        updateSideAppearance()
    }
    
    private func createCard(content: () -> UIView) -> UIView {
        let card = UIView()
        card.backgroundColor = .systemBackground
        card.layer.cornerRadius = 12
        
        let inner = content()
        inner.translatesAutoresizingMaskIntoConstraints = false
        card.addSubview(inner)
        
        NSLayoutConstraint.activate([
            inner.topAnchor.constraint(equalTo: card.topAnchor, constant: 16),
            inner.leadingAnchor.constraint(equalTo: card.leadingAnchor, constant: 16),
            inner.trailingAnchor.constraint(equalTo: card.trailingAnchor, constant: -16),
            inner.bottomAnchor.constraint(equalTo: card.bottomAnchor, constant: -16)